/**
 * Satoshi (Medium 500 + Bold 700) embedded as base64 for the OG card renderer
 * (api/og/voter.ts). Satori — which @vercel/og uses — accepts only TTF/OTF/WOFF.
 *
 * Source: Fontshare "Satoshi" by the Indian Type Foundry
 * (https://www.fontshare.com/fonts/satoshi), free under the ITF Free Font
 * License. Subsetted to Latin + Latin-1/Extended + smart punctuation with
 * fonttools to keep the edge bundle small; glyphs outside that range fall back
 * to the renderer's default sans. This is a deliberate copy of ~this app's
 * brand font, embedded so the OG endpoint has NO runtime network dependency:
 * a CDN fetch on every cold render added latency and, with no timeout, could
 * hang to the 25s edge limit -> 504 (crawlers then drop the card).
 *
 * Regenerate (from the Fontshare "Satoshi" download zip):
 *   pyftsubset Satoshi-<Weight>.ttf \
 *     --unicodes="U+0020-007E,U+00A0-024F,U+2013,U+2014,U+2018-201A,U+201C-201E,U+2020-2022,U+2026,U+2032,U+2033,U+2039,U+203A,U+20AC,U+2122" \
 *     --layout-features='kern,liga,calt' --no-hinting --desubroutinize \
 *     --output-file=Satoshi-<Weight>.subset.ttf
 * then base64-encode each subset file into the constants below.
 */
export const SATOSHI_MEDIUM_BASE64 =
  ''

export const SATOSHI_BOLD_BASE64 =
  ''
